function escapeHtml(text) {
  const map = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  };
  return String(text).replace(/[&<>"']/g, m => map[m]);
}

// Consent endpoint
app.post('/authorize/consent', (req, res) => {
  const { request_id, username, password, action } = req.body;
  
  const authRequest = authorizationCodes.get(request_id);
  if (!authRequest || authRequest.type !== 'pending') {
    return res.status(400).send('Invalid or expired authorization request');
  }
  
  // Check if request is expired (5 minutes)
  if (Date.now() - authRequest.createdAt > 300000) {
    authorizationCodes.delete(request_id);
    return res.status(400).send('Authorization request expired');
  }
  
  const user = users.get(username);
  const hashedPassword = crypto.createHash('sha256').update(password).digest('hex');
  
  if (!user || user.password !== hashedPassword) {
    return res.status(401).send('Invalid credentials');
  }
  
  if (action !== 'approve') {
    const redirectUrl = new url.URL(authRequest.redirectUri);
    redirectUrl.searchParams.set('error', 'access_denied');
    if (authRequest.state) {
      redirectUrl.searchParams.set('state', authRequest.state);
    }
    authorizationCodes.delete(request_id);
    return res.redirect(redirectUrl.toString());
  }
  
  // Generate authorization code
  const code = generateSecureToken();
  
  authorizationCodes.set(code, {
    clientId: authRequest.clientId,
    redirectUri: authRequest.redirectUri,
    scope: authRequest.scope,
    username: username,
    createdAt: Date.now(),
    type: 'code',
    used: false
  });
  
  // Clean up pending request
  authorizationCodes.delete(request_id);
  
  // Redirect back to client with authorization code
  const redirectUrl = new url.URL(authRequest.redirectUri);
  redirectUrl.searchParams.set('code', code);
  if (authRequest.state) {
    redirectUrl.searchParams.set('state', authRequest.state);
  }
  
  res.redirect(redirectUrl.toString());
});

// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;
  
  // Validate grant type
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }
  
  // Validate client credentials
  if (!client_id || !client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  const client = clients.get(client_id);
  const hashedSecret = crypto.createHash('sha256').update(client_secret).digest('hex');
  
  if (!client || client.clientSecret !== hashedSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  // Validate authorization code
  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'code is required' });
  }
  
  const authCode = authorizationCodes.get(code);
  
  if (!authCode || authCode.type !== 'code') {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  // Check if code is expired (10 minutes)
  if (Date.now() - authCode.createdAt > 600000) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'authorization code expired' });
  }
  
  // Check if code was already used
  if (authCode.used) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'authorization code already used' });
  }
  
  // Validate client ID matches
  if (authCode.clientId !== client_id) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  // Validate redirect URI matches
  if (authCode.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'redirect_uri mismatch' });
  }
  
  // Mark code as used
  authCode.used = true;
  
  // Generate access token
  const accessToken = generateSecureToken(48);
  const refreshToken = generateSecureToken(48);
  
  accessTokens.set(accessToken, {
    clientId: client_id,
    username: authCode.username,
    scope: authCode.scope,
    createdAt: Date.now(),
    expiresIn: 3600
  });
  
  // Clean up authorization code after short delay
  setTimeout(() => authorizationCodes.delete(code), 60000);
  
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: authCode.scope
  });
});

